request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelId ?idType ?orgId ?choreo ?participant ?participantName WHERE {
  ?model a bboExt:Model .

  {
    ?model tai:normalizedId ?modelId .
    BIND("normalizedId" AS ?idType)
  }
  UNION
  {
    ?model tai:originalId ?modelId .
    BIND("originalId" AS ?idType)
  }
  FILTER(?modelId = "6c9090aeef814120944b4885c7343b63")

  ?model tai:belongsTo ?org .
  ?org tai:organizationId ?orgId .

  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?defs .

  {
    ?participant a bboExt:Participant .
    ?participant tai:belongsTo ?choreo .
  }
  UNION
  {
    ?participant tai:belongsTo ?choreo .
    ?participant bbo:name ?participantName .
    FILTER(!isBlank(?participant))
  }

  OPTIONAL { ?participant bbo:name ?participantName . }
}
ORDER BY ?participantName
LIMIT 25
